// @vitest-environment node
/**
 * SPEC-019: Aviso de consentimiento de grabación (mitad main): el registro de
 * consentimiento se persiste en el `.transcript.json` junto a
 * lines/latency/assistant, y las grabaciones sin reconocimiento (spike
 * /capture) persisten `consent: null` sin error.
 * Generated by QA Dev agent.
 *
 * Mismo arnés que transcriptionService.test.ts (SPEC-002): DeepgramConnection
 * mockeada (sin red) y persistencia con fs real en directorio temporal. El
 * cableado IPC completo (recording:start captura el timestamp → recording:stop
 * lo consume y resetea) vive en ipcMain y queda como verificación manual.
 */
import { mkdtempSync, readFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import type { WebContents } from 'electron'
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import type { DeepgramCallbacks } from '../../../src/main/deepgramService'
import {
  persistTranscript,
  resetTranscription,
  startTranscription
} from '../../../src/main/transcriptionService'
import type { TranscriptConsent } from '../../../src/renderer/src/types/audio'

interface FakeConnection {
  apiKey: string
  callbacks: DeepgramCallbacks
  opened: boolean
  isOpen: boolean
  sendAudio: ReturnType<typeof vi.fn>
  sendKeepAlive: ReturnType<typeof vi.fn>
  closeStream: ReturnType<typeof vi.fn>
  terminate: ReturnType<typeof vi.fn>
}

const harness = vi.hoisted(() => ({
  instances: [] as unknown[]
}))

vi.mock('../../../src/main/deepgramService', () => ({
  DeepgramConnection: class {
    apiKey: string
    callbacks: DeepgramCallbacks
    opened = false
    isOpen = false
    sendAudio = vi.fn(() => true)
    sendKeepAlive = vi.fn()
    closeStream = vi.fn()
    terminate = vi.fn()

    constructor(apiKey: string, callbacks: DeepgramCallbacks) {
      this.apiKey = apiKey
      this.callbacks = callbacks
      harness.instances.push(this)
    }
  },
  classifyConnectionFailure: vi.fn(() => Promise.resolve('other' as const))
}))

/** Forma persistida del transcript: { lines, latency, assistant, consent } (SPEC-019). */
interface PersistedTranscript {
  lines: Array<{ channel: string; text: string }>
  latency: { count: number } | null
  assistant: unknown
  consent: TranscriptConsent | null
}

function createSender(): WebContents {
  const senderLike = {
    isDestroyed: (): boolean => false,
    send: vi.fn()
  }
  return senderLike as unknown as WebContents
}

/** Arranca una sesión de transcripción con una línea final recibida. */
function startSessionWithOneFinalLine(): void {
  startTranscription(createSender())
  const connection = harness.instances[0] as FakeConnection
  connection.opened = true
  connection.isOpen = true
  connection.callbacks.onOpen()
  connection.callbacks.onResult({
    channelIndex: 0,
    transcript: 'hola desde el micro',
    isFinal: true,
    startSeconds: 0,
    durationSeconds: 1,
    speaker: null
  })
}

function readTranscript(transcriptPath: string | null): PersistedTranscript {
  if (transcriptPath === null) {
    throw new Error('persistTranscript devolvió null con líneas finales recibidas')
  }
  return JSON.parse(readFileSync(transcriptPath, 'utf8')) as PersistedTranscript
}

beforeEach(() => {
  vi.clearAllMocks()
  harness.instances.length = 0
  resetTranscription()
  process.env['DEEPGRAM_API_KEY'] = 'dg-test-key'
})

afterEach(() => {
  resetTranscription()
  delete process.env['DEEPGRAM_API_KEY']
})

describe('transcriptionService (consentimiento SPEC-019)', () => {
  // SPEC-019 · AC-09 (mitad main: el registro viaja al transcript persistido)
  it('persists the consent record with its acknowledgedAt timestamp in the transcript.json', () => {
    startSessionWithOneFinalLine()
    const dir = mkdtempSync(join(tmpdir(), 'maurya-consent-'))
    const wavPath = join(dir, 'entrevista.wav')
    const consent: TranscriptConsent = { acknowledgedAt: '2026-07-10T10:15:00.000Z' }

    const { transcriptPath } = persistTranscript(wavPath, null, consent)

    const persisted = readTranscript(transcriptPath)
    // El registro de consentimiento acompaña a la transcripción, con su marca
    expect(persisted.consent).toEqual({ acknowledgedAt: '2026-07-10T10:15:00.000Z' })
    // …sin alterar el resto de la forma { lines, latency, assistant }
    expect(persisted.lines).toHaveLength(1)
    expect(persisted.lines[0].text).toBe('hola desde el micro')
    expect(persisted.latency).not.toBeNull()
    expect(persisted.assistant).toBeNull()
  })

  // SPEC-019 · AC-10 (grabación del spike /capture: sin reconocimiento → null)
  it('persists consent as null without error when the recording had no acknowledgement (spike flow)', () => {
    startSessionWithOneFinalLine()
    const dir = mkdtempSync(join(tmpdir(), 'maurya-consent-null-'))
    const wavPath = join(dir, 'spike.wav')

    // El spike llama recording:start sin interviewId ni consentimiento: main
    // persiste sin el tercer argumento
    const { transcriptPath, latency } = persistTranscript(wavPath)

    expect(latency).not.toBeNull()
    const persisted = readTranscript(transcriptPath)
    expect(persisted.consent).toBeNull()
    expect(persisted.lines).toHaveLength(1)
  })
})
